521→function queueAudio(arrayBuf) {
522→  if (!playbackCtx) return;
523→  const int16 = new Int16Array(arrayBuf);
524→  const float32 = new Float32Array(int16.length);
525→  for (let i = 0; i < int16.length; i++) {
526→    float32[i] = int16[i] / 32768;
527→  }
528→  const buffer = playbackCtx.createBuffer(1, float32.length, 24000);
529→  buffer.copyToChannel(float32, 0);
530→  const source = playbackCtx.createBufferSource();
531→  source.buffer = buffer;
532→  source.connect(playbackCtx.destination);
533→  const now = playbackCtx.currentTime;
534→  const startTime = Math.max(now + 0.01, nextPlayTime);
535→  source.start(startTime);
536→  nextPlayTime = startTime + buffer.duration;
537→}
