552→function drawMidiBars() {
553→  const canvas = document.getElementById('midiBars');
554→  const ctx = canvas.getContext('2d');
555→  const dpr = window.devicePixelRatio || 1;
556→  const rect = canvas.getBoundingClientRect();
557→  canvas.width = rect.width * dpr;
558→  canvas.height = 140 * dpr;
559→  ctx.scale(dpr, dpr);
560→  const W = rect.width;
561→  const H = 140;
562→
563→  ctx.clearRect(0, 0, W, H);
564→
565→  if (!analyser) return;
566→  const freqData = new Uint8Array(analyser.frequencyBinCount);
567→  analyser.getByteFrequencyData(freqData);
568→
569→  // Map frequency bins to piano-relevant bands (27.5Hz A0 to 4186Hz C8)
570→  // With 16kHz sample rate and FFT size 2048: bin resolution = 16000/2048 ≈ 7.8 Hz
571→  // Piano range: bin ~3 (27.5Hz) to bin ~537 (4186Hz)
572→  const binRes = 16000 / 2048;
573→  const startBin = Math.floor(27.5 / binRes);
574→  const endBin = Math.min(Math.ceil(4200 / binRes), freqData.length - 1);
575→  const numBars = 48;
576→  const binsPerBar = Math.max(1, Math.floor((endBin - startBin) / numBars));
577→  const barWidth = (W - 20) / numBars;
578→  const gap = 2;
579→
580→  for (let i = 0; i < numBars; i++) {
581→    let sum = 0;
582→    const from = startBin + i * binsPerBar;
583→    const to = Math.min(from + binsPerBar, freqData.length);
584→    for (let b = from; b < to; b++) sum += freqData[b];
585→    const avg = sum / (to - from);
586→    const normH = (avg / 255) * (H - 10);
587→
588→    // Color gradient: bass=blue/purple, mid=amber, treble=rose
589→    const t = i / numBars;
590→    let r, g, b_c;
591→    if (t < 0.33) {
592→      // purple to blue
593→      const lt = t / 0.33;
594→      r = 167 - lt * 20; g = 139 + lt * 58; b_c = 250;
595→    } else if (t < 0.66) {
596→      // blue to amber
597→      const lt = (t - 0.33) / 0.33;
598→      r = 147 + lt * 104; g = 197 - lt * 6; b_c = 253 - lt * 217;
599→    } else {
600→      // amber to rose
601→      const lt = (t - 0.66) / 0.34;
602→      r = 251; g = 191 - lt * 78; b_c = 36 + lt * 97;
603→    }
604→
605→    const x = 10 + i * barWidth;
606→    const barW = barWidth - gap;
607→
608→    // Glow effect
609→    ctx.shadowBlur = normH > 40 ? 8 : 0;
610→    ctx.shadowColor = `rgba(${r},${g},${b_c},0.4)`;
611→
612→    // Bar
613→    const gradient = ctx.createLinearGradient(0, H, 0, H - normH);
614→    gradient.addColorStop(0, `rgba(${r},${g},${b_c},0.15)`);
615→    gradient.addColorStop(1, `rgba(${r},${g},${b_c},0.8)`);
616→    ctx.fillStyle = gradient;
617→    ctx.fillRect(x, H - normH, barW, normH);
618→
619→    // Top cap
620→    ctx.shadowBlur = 0;
621→    ctx.fillStyle = `rgba(${r},${g},${b_c},0.9)`;
622→    ctx.fillRect(x, H - normH, barW, 2);
623→  }
624→}
