785→  const div = document.createElement('div');
786→  div.className = 'msg ' + role;
787→  if (role === 'system') {
788→    div.textContent = text;
789→  } else {
790→    const roleLabel = document.createElement('div');
791→    roleLabel.className = 'role';
792→    roleLabel.textContent = role === 'user' ? 'YOU' : 'PIANOQUEST';
793→    div.appendChild(roleLabel);
794→    const content = document.createElement('div');
795→    content.className = 'content';
796→    content.textContent = text;
797→    div.appendChild(content);
798→  }
